from pathlib import Path

import pytest

AC_UID = "ea4c2e44ca7a4e55"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
TARGET_FILES = [
    REPO_ROOT / "README.md",
    REPO_ROOT / "INDEX.md",
    REPO_ROOT / ".claude" / "INDEX.md",
]


def test_AC_08():
    """
    GIVEN: README.md, INDEX.md, .claude/INDEX.md are read as text
    WHEN:  grep -c 'agent-scores' across all three files
    THEN:  total count across all three files MUST be 0
    """
    offenders = []
    for f in TARGET_FILES:
        assert f.is_file(), f"missing required file: {f}"
        text = f.read_text(encoding="utf-8")
        count = text.count("agent-scores")
        if count > 0:
            # Capture line numbers for actionable failure
            hits = [
                (i + 1, line)
                for i, line in enumerate(text.splitlines())
                if "agent-scores" in line
            ]
            offenders.append((str(f), count, hits))
    assert not offenders, (
        f"'agent-scores' leak found in INDEX/README files (total must be 0): {offenders}"
    )
